/**
 * NW1 resampler FIR coefficients — `gFIRCoeffs` extracted verbatim from the Nord
 * Sample Editor (arm64 slice, data symbol @0x1007e82e4). A unity-DC lowpass
 * windowed-sinc: **15 taps × 512 sub-phases**, laid out `g[tap*512 + phase]`
 * (float32 LE). Used by {@link resampleNW1} for WAV → internal-rate conversion.
 *
 * DO NOT hand-edit — regenerate from the binary (`opennord-re/DumpSym.java`,
 * `NSM_SYMS=gFIRCoeffs NSM_LEN=30720`). See `docs/NSMP-CODEC.md`.
 *
 * ⚠️ SCOPE (docs/LEGAL.md): an interoperability filter table, not sample content.
 */

/** Sub-phase count (fractional resolution) of the polyphase FIR. */
export const FIR_PHASES = 512;
/** Taps per phase (kernel half-width; the kernel is applied symmetrically). */
export const FIR_TAPS = 15;

const FIR_B64 =
  '';

/** Decode the FIR table to a Float32Array (7680 = FIR_TAPS × FIR_PHASES). */
export function loadFirCoeffs(): Float32Array {
  const bin = typeof atob === 'function'
    ? atob(FIR_B64)
    : Buffer.from(FIR_B64, 'base64').toString('binary');
  const bytes = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
  return new Float32Array(bytes.buffer, bytes.byteOffset, bytes.byteLength >> 2);
}
